import os

original_b64 = "_c3NsbW9kZT1kaXNhYmxlJmNvbm5lY3Rpb25fbGltaXQ9MTAmY29ubmVjdF90aW1lb3V0PTAmbWF4X2lkbGVfY29ubmVjdGlvbl9saWZldGltZT0wJnBvb2xfdGltZW91dD0wJnNvY2tldF90aW1lb3V0PTAifQ"

# Reconstruct the URL with the new proxy port 51602
new_db_url = f"prisma+postgres://localhost:51602/?api_key={original_b64}"

with open(".env", "r") as f:
    lines = f.readlines()
    
with open(".env", "w") as f:
    for line in lines:
        if line.startswith("DATABASE_URL="):
            f.write(f'DATABASE_URL="{new_db_url}"\n')
        else:
            f.write(line)

print("Successfully restored and updated DATABASE_URL in .env!")
